UPDATE ai_chat_session
SET session_name = #{sessionName}, update_time = #{updateTime}
WHERE session_id = #{sessionId}

UPDATE ai_chat_session
SET message_count = message_count + 1,
    last_message_time = #{lastMessageTime},
    update_time = #{lastMessageTime}
WHERE session_id = #{sessionId}

UPDATE ai_message
SET feedback_score = #{feedbackScore},
    feedback_comment = #{feedbackComment}
WHERE message_id = #{messageId}

UPDATE ai_favorite_query
SET execution_count = execution_count + 1,
    last_execute_time = #{lastExecuteTime}
WHERE id = #{id}

UPDATE ai_scheduled_query
SET last_run_time = #{lastRunTime},
    next_run_time = #{nextRunTime}
WHERE id = #{id}
